import React, { useState, useEffect } from "react";
import {
  ComposableMap,
  Geographies,
  Geography,
  ZoomableGroup
} from "react-simple-maps";
import { scaleQuantize } from "d3-scale";
import { csv } from "d3-fetch";
import { usePapaParse } from 'react-papaparse';

const geoUrl = "https://cdn.jsdelivr.net/npm/us-atlas@3/counties-10m.json";

const colorScale = scaleQuantize()
  .domain([1, 10])
  .range([
    "#ffedea",
    "#ffcec5",
    "#ffad9f",
    "#ff8a75",
    "#ff5533",
    "#e2492d",
    "#be3d26",
    "#9a311f",
    "#782618"
  ]);

const MapChart = ({ setTooltipContent }) => {
  const [data, setData] = useState([]);
  const { readRemoteFile } = usePapaParse();
  useEffect(() => {
    // https://www.bls.gov/lau/
    const csvFilePath = 'https://hxib9w.csb.app/unemployment-by-county-2017.csv';
    try {
        csv(csvFilePath).then((counties) => {
            setData(counties);
          });
    } catch (e) {
        console.log('csv error', e);
    }
    // readRemoteFile(csvFilePath, {
    //     complete: (results) => {
    //       console.log('---------------------------');
    //       console.log('Results:', results);
    //       console.log('---------------------------');
    //     },
    //   });
  }, []);
  return (
    <>
      <ComposableMap data-tip="" projection="geoAlbersUsa">
        <ZoomableGroup zoom={1}>
          <Geographies geography={geoUrl}>
            {({ geographies }) =>
              geographies.map((geo) => {
                const cur = data.find((s) => s.id === geo.id);
                return (
                  <Geography
                    key={geo.rsmKey}
                    geography={geo}
                    onMouseEnter={() => {
                      setTooltipContent(
                        `${cur ? cur.name : null} — ${
                          cur ? cur.unemployment_rate : null
                        }`
                      );
                    }}
                    onMouseLeave={() => {
                      setTooltipContent("");
                    }}
                    style={{
                      default: {
                        fill: "#D6D6DA",
                        outline: "none"
                      },
                      hover: {
                        fill: colorScale(cur ? cur.unemployment_rate : "#EEE"),
                        outline: "none"
                      },
                      pressed: {
                        fill: "#00a4b7",
                        outline: "none"
                      }
                    }}
                  />
                );
              })
            }
          </Geographies>
        </ZoomableGroup>
      </ComposableMap>
    </>
  );
};

export default MapChart;